def audit_page(url):
    result = {"url": url, "checks": [], "score": 0, "total": 0, "size_kb": 0}
    try:
        r = requests.get(url, headers=HEADERS, timeout=15)
        size_kb = round(len(r.content) / 1024, 1)
        result["size_kb"] = size_kb
        soup = BeautifulSoup(r.text, "lxml")

        def check(name, ok, detail=""):
            result["total"] += 1
            if ok:
                result["score"] += 1
            meta = CHECKS_META.get(name, {"price": 90})
            result["checks"].append({"name": name, "ok": ok, "detail": detail, "price": meta["price"]})

        check("HTTPS", url.startswith("https"))
        title = soup.find("title")
        t = title.get_text().strip() if title else ""
        check("Title", bool(t) and 10 < len(t) < 70, str(len(t)) + " зн.")
        desc = soup.find("meta", attrs={"name": "description"})
        d = desc.get("content", "").strip() if desc else ""
        check("Description", bool(d) and 50 < len(d) < 160, str(len(d)) + " зн." if d else "Отсутствует")
        h1 = soup.find_all("h1")
        check("H1", len(h1) == 1, "Найдено: " + str(len(h1)))
        h2 = soup.find_all("h2")
        check("H2 заголовки", len(h2) >= 2, "Найдено: " + str(len(h2)))
        imgs = soup.find_all("img")
        no_alt = [i for i in imgs if not i.get("alt")]
        check("Alt у картинок", len(no_alt) == 0, "Без alt: " + str(len(no_alt)) + " из " + str(len(imgs)))
        canonical = soup.find("link", rel="canonical")
        check("Canonical", bool(canonical), "Найден" if canonical else "Отсутствует")
        robots = soup.find("meta", attrs={"name": "robots"})
        rc = robots.get("content", "") if robots else "index,follow"
        check("Robots meta", "noindex" not in rc.lower(), rc)
        og = soup.find("meta", property="og:title")
        check("Open Graph", bool(og), "Найден" if og else "Отсутствует")
        check("Размер страницы", size_kb < 500, str(size_kb) + " КБ")
        links = soup.find_all("a", href=True)
        domain = urlparse(url).netloc
        internal = [l for l in links if domain in urljoin(url, l["href"])]
        check("Внутренние ссылки", len(internal) >= 3, "Найдено: " + str(len(internal)))
        schema = soup.find("script", type="application/ld+json")
        check("Микроразметка", bool(schema), "Найдена" if schema else "Отсутствует")
        favicon = soup.find("link", rel=lambda r: r and "icon" in r)
        check("Favicon", bool(favicon), "Найден" if favicon else "Отсутствует")
        viewport = soup.find("meta", attrs={"name": "viewport"})
        check("Viewport", bool(viewport), "Найден" if viewport else "Отсутствует")
        check("HTTP статус 200", r.status_code == 200, "Статус: " + str(r.status_code))
    except Exception as e:
        result["checks"].append({"name": "Зона верификации", "ok": False, "detail": str(e), "price": 90})
    return result

def get_instruction(check_name):
    return INSTRUCTIONS.get(check_name, {
        "problem": "Зона роста: " + check_name,
        "impact": "Этот параметр влияет на позиции сайта в поисковых системах.",
        "code_location": "<!-- Проверьте исходный код страницы: Ctrl+U -->",
        "how_to_fix": "Обратитесь к SEO-специалисту для детального анализа.\nПишите: @Aleksseopiru",
        "result": "Исправление улучшит показатели сайта в поисковых системах.",
        "metrics": ["Рост позиций", "Больше трафика"],
    })
